+
+    #[test]
+    fn mcp_tool_has_correct_name() {
+        let op = sample_read_op();
+        let tool = to_mcp_tool(&op, &ExportOptions::default());
+        assert_eq!(tool.name, "github.list_issues");
+    }
+
+    #[test]
+    fn mcp_tool_has_input_schema() {
+        let op = sample_read_op();
+        let tool = to_mcp_tool(&op, &ExportOptions::default());
